#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (!s || !out)
        return 0;

    const char *p = s;

    /* skip leading whitespace */
    while (*p && isspace((unsigned char)*p))
        p++;

    if (!*p)
        return 0;

    /* optional sign */
    int neg = 0;
    if (*p == '-') {
        neg = 1;
        p++;
    } else if (*p == '+') {
        p++;
    }

    if (!*p || !isdigit((unsigned char)*p))
        return 0;

    /* parse digits with overflow/underflow guard */
    int32_t acc = 0;
    const int32_t hi  = neg ? (int32_t)INT32_MIN / 10 : INT32_MAX / 10;
    const int32_t lo  = neg ? (int32_t)INT32_MIN % 10 : INT32_MAX % 10;

    while (isdigit((unsigned char)*p)) {
        int digit = *p - '0';

        /* reject leading zeros after the first digit */
        if (acc == 0 && digit == 0) {
            p++;
            continue;
        }

        if (acc > hi || (acc == hi && digit > lo))
            return 0;

        acc = acc * 10 + digit;
        p++;
    }

    /* apply sign */
    int32_t val = neg ? -(acc) : acc;

    /* reject underflow: -(acc) overflows only when acc > INT32_MAX+1,
       which cannot happen here because hi/lo already guard against it.
       But for the edge case INT32_MIN itself (acc == INT32_MAX+1),
       negating works correctly in two's complement. */

    /* skip trailing whitespace */
    while (*p && isspace((unsigned char)*p))
        p++;

    if (*p)
        return 0;

    *out = val;
    return 1;
}

