#include <stdint.h>
#include <inttypes.h>
#include <limits.h>

extern int parse_int32(const char *s, int32_t *out);

#define TEST(s, expected, expected_val) do { \
    int32_t val; \
    int r = parse_int32(s, &val); \
    const char *status = (r == expected && (!expected || val == expected_val)) ? "PASS" : "FAIL"; \
    printf("%s parse_int32(\"%s\") = %d, val=%" PRId32 " (expected %d, %" PRId32 ")\n", \
           status, s, r, val, expected, expected_val); \
} while(0)

int main(void) {
    /* basic */
    TEST("42", 1, 42);
    TEST("-42", 1, -42);
    TEST("+42", 1, 42);
    TEST("0", 1, 0);
    TEST("-0", 1, 0);

    /* whitespace */
    TEST("  42  ", 1, 42);
    TEST("\t-100\n", 1, -100);
    TEST("   ", 0, 0);

    /* boundaries */
    TEST("2147483647", 1, INT32_MAX);
    TEST("-2147483648", 1, INT32_MIN);
    TEST("2147483648", 0, 0);
    TEST("-2147483649", 0, 0);

    /* rejects */
    TEST("", 0, 0);
    TEST("abc", 0, 0);
    TEST("42abc", 0, 0);
    TEST("42.0", 0, 0);
    TEST("++42", 0, 0);
    TEST("-+42", 0, 0);
    TEST("4 2", 0, 0);

    /* leading zeros */
    TEST("00042", 1, 42);
    TEST("-00042", 1, -42);

    return 0;
}
